export function FloatingPalette({
  mode,
  activeTool,
  onToolSelect,
  disabledContext,
  allowedToolIds,
}: {
  mode: WorkspaceMode;
  activeTool: ToolId;
  onToolSelect: (id: ToolId) => void;
