    case 'visibility-graphics':
      return 'visibility.plan.graphics';
    case 'family-library':
      return 'library.open-family';
    case 'project-menu':
      return 'project.open-menu';
    case 'settings':
      return 'help.keyboard-shortcuts';
  }
  return null;
}

