    const availability = evaluateCommandInMode('tool.wall', '3d');
    expect(availability?.state).toBe('bridge');
    if (availability?.state === 'bridge') {
      expect(availability.targetMode).toBe('plan');
      expect(availability.reason).toContain('Plan');
    }
